import React, { useState, useEffect } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    CategoriaID: null,
    Nombre: "",
  });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // 🔧 NORMALIZACIÓN DE DATOS (CLAVE)
  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");

      setCategorias(
        res.data.map((c) => ({
          CategoriaID: c.CategoriaID ?? c.categoria_id,
          Nombre: c.Nombre ?? c.nombre ?? "",
        }))
      );
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({
      ...categoriaActual,
      [e.target.name]: e.target.value,
    });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ CategoriaID: null, Nombre: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (categoria) => {
    setCategoriaActual({
      CategoriaID: categoria.CategoriaID,
      Nombre: categoria.Nombre,
    });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.CategoriaID}`,
          { Nombre: categoriaActual.Nombre }
        );
      } else {
        await axios.post("http://localhost:5000/api/categorias", {
          Nombre: categoriaActual.Nombre,
        });
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  // 🔎 Filtrado (PROTEGIDO)
  const categoriasFiltradas = categorias.filter((c) =>
    (c.Nombre || "").toLowerCase().includes(busqueda.toLowerCase())
  );

  // 📄 Paginación
  const totalPaginas = Math.ceil(
    categoriasFiltradas.length / categoriasPorPagina
  );
  const indiceInicio = (paginaActual - 1) * categoriasPorPagina;
  const categoriasPaginadas = categoriasFiltradas.slice(
    indiceInicio,
    indiceInicio + categoriasPorPagina
  );

  const cambiarPagina = (pagina) => setPaginaActual(pagina);

  return (
    <div className="container mt-5">
      {/* Buscador y botón */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          className="form-control w-50"
          placeholder="Buscar categoría..."
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />
        <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
          ➕ Agregar Categoría
        </button>
      </div>

      {/* Cards */}
      <div className="row">
        {categoriasPaginadas.map((cat) => (
          <div key={cat.CategoriaID} className="col-md-4 mb-4">
            <div className="card shadow-sm h-100">
              <div className="card-body d-flex flex-column justify-content-between">
                <h5 className="card-title">{cat.Nombre}</h5>

                <div className="d-flex justify-content-between mt-3">
                  <button
                    className="btn btn-warning btn-sm"
                    onClick={() => abrirModalEditar(cat)}
                  >
                    ✏️ Editar
                  </button>
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => eliminarCategoria(cat.CategoriaID)}
                  >
                    🗑️ Eliminar
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}

        {categoriasPaginadas.length === 0 && (
          <p className="text-center text-muted">
            No hay categorías para mostrar
          </p>
        )}
      </div>

      {/* Paginación */}
      {totalPaginas > 1 && (
        <nav className="d-flex justify-content-center mt-4">
          <ul className="pagination">
            <li className={`page-item ${paginaActual === 1 ? "disabled" : ""}`}>
              <button
                className="page-link"
                onClick={() => cambiarPagina(paginaActual - 1)}
              >
                Anterior
              </button>
            </li>

            {Array.from({ length: totalPaginas }, (_, i) => (
              <li
                key={i}
                className={`page-item ${
                  paginaActual === i + 1 ? "active" : ""
                }`}
              >
                <button
                  className="page-link"
                  onClick={() => cambiarPagina(i + 1)}
                >
                  {i + 1}
                </button>
              </li>
            ))}

            <li
              className={`page-item ${
                paginaActual === totalPaginas ? "disabled" : ""
              }`}
            >
              <button
                className="page-link"
                onClick={() => cambiarPagina(paginaActual + 1)}
              >
                Siguiente
              </button>
            </li>
          </ul>
        </nav>
      )}

      {/* Modal */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4">
              <div className="modal-header">
                <h5 className="modal-title">
                  {modoEdicion ? "Editar Categoría" : "Nueva Categoría"}
                </h5>
                <button
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>

              <form onSubmit={guardarCategoria}>
                <div className="modal-body">
                  <label className="form-label">Nombre</label>
                  <input
                    type="text"
                    name="Nombre"
                    className="form-control"
                    value={categoriaActual.Nombre}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="modal-footer">
                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={() => setShowModal(false)}
                  >
                    Cancelar
                  </button>
                  <button type="submit" className="btn btn-primary">
                    Guardar
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
